mapper.select:
SELECT B1.* FROM ( SELECT requestNo, statusCd, statusNm, deployTypeNm, objectClassCd2, objectClassNm2, objectNo, objectNm, revNo, businessAreaCd, businessAreaNm, /* 사업장 */ requestDeptNm, requestUserNm, TO_CHAR(TO_DATE(requestDt, 'YYYYMMDD'), 'YYYY-MM-DD') AS requestDt, approvalUserNm, TO_CHAR(approvalDt, 'YYYY-MM-DD') AS approvalDt, deployCount, TO_CHAR(TO_DATE(validPeriod, 'YYYYMMDD'), 'YYYY-MM-DD') AS validPeriod, accptUserCount || '/' || userCountToAccept AS acceptUser, objectType, objectTypeNm, ROW_NUMBER() OVER (ORDER BY requestDt DESC) AS PAGEINDEX FROM ( SELECT request.REQUEST_NO AS requestNo, /* 요청번호 */ request.REQUEST_PURPOSE AS deployTypeCd, /* 배포유형 */ FN_GET_CD_NM('deployType', request.REQUEST_PURPOSE, #{sessionLang}) AS deployTypeNm, request.OBJECT_TYPE AS objectType, /* 자료구분 */ FN_GET_CD_NM('objectType', request.OBJECT_TYPE, #{sessionLang}) AS objectTypeNm, /* 자료유형 */ request.STATUS_CD AS statusCd, /* 진행상태 */ FN_GET_CD_NM('requestStatusCd', request.STATUS_CD, #{sessionLang}) AS statusNm, requestMapping.OBJECT_CLASS_CD2 AS objectClassCd2, /* 자료유형코드 */ requestMapping.OBJECT_CLASS_NM2 AS objectClassNm2, /* 자료유형 */ requestMapping.OBJECT_NO AS objectNo, /* 문서번호 */ requestMapping.OBJECT_NM AS objectNm, /* 문서명 */ requestMapping.REV_NO AS revNo, /* REV */ requestMapping.BUSINESS_AREA_CD AS businessAreaCd, /* 사업장코드 */ FN_GET_CD_NM('businessAreaCd', requestMapping.BUSINESS_AREA_CD, #{sessionLang}) AS businessAreaNm, /* 사업장 */ deployDept.DEPT_CD AS requestDeptCd, /* 배포부서 */ deployDept.DEPT_NM AS requestDeptNm, /* 배포부서 */ deployUser.USER_CD AS requestUserCd, /* 배포자 */ deployUser.USER_NM AS requestUserNm, /* 배포자 */ request.USE_START_YMD AS requestDt, /* 배포일 */ ( SELECT appuser.USER_NM FROM DOCS_REQUEST_DETAIL appinfo, DOCS_USER appuser WHERE appinfo.REQUEST_NO = request.REQUEST_NO AND appinfo.ACTUAL_USER_CD = appuser.USER_CD AND appinfo.APPROVAL_STATUS_CD = 'APPROVAL' ) AS approvalUserNm, /* 결재자 */ ( SELECT appinfo.ACTION_DT FROM DOCS_REQUEST_DETAIL appinfo WHERE appinfo.REQUEST_NO = request.REQUEST_NO AND appinfo.APPROVAL_STATUS_CD = 'APPROVAL' ) AS approvalDt, /* 결재일 */ COALESCE(( SELECT SUM(DEPLOY_COUNT) FROM DOCS_DEPLOY_INFO tmp WHERE tmp.REQUEST_NO = requestMapping.REQUEST_NO AND tmp.OBJECT_ID = requestMapping.OBJECT_ID ), 0) AS deployCount, /* 배포매수 */ request.USE_END_YMD AS validPeriod, /* 유효기간 */ ( SELECT COUNT(DEPLOY_USER_CD) FROM DOCS_REQUEST_DEPLOY tmpDeploy WHERE tmpDeploy.REQUEST_NO = request.REQUEST_NO ) AS userCountToAccept, ( SELECT COUNT(DEPLOY_USER_CD) FROM DOCS_REQUEST_DEPLOY tmpDeploy WHERE tmpDeploy.REQUEST_NO = request.REQUEST_NO AND ACCEPT_YN = 'Y' ) AS accptUserCount FROM DOCS_REQUEST request INNER JOIN ( SELECT REQUEST_NO, MAX(OBJECT_ID) AS OBJECT_ID, SUM(0) AS DEPLOY_COUNT FROM DOCS_REQUEST_MAPPING tmpMapping GROUP BY REQUEST_NO ) tmpMapping ON tmpMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = tmpMapping.REQUEST_NO AND requestMapping.OBJECT_ID = tmpMapping.OBJECT_ID INNER JOIN DOCS_USER deployUser ON deployUser.USER_CD = request.INSERT_USER_CD INNER JOIN DOCS_DEPT deployDept ON deployDept.DEPT_CD = deployUser.DEPT_CD WHERE REQUEST_TYPE = 'PRODUCT' AND REQUEST_PURPOSE IN ('NEW', 'REPLACE')
AND TO_DATE(request.USE_START_YMD, 'YYYY-MM-DD') BETWEEN TO_DATE(#{deployStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{deployEndDt}, 'YYYY-MM-DD')
ORDER BY requestDt DESC
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1=1
AND objectNo LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND objectClassCd2 = #{objectClassCd2}
AND requestUserCd = #{requestUserCd}
AND businessAreaCd = #{businessAreaCd}
AND objectType = #{objectType}
AND statusCd = #{statusCd}
AND PAGEINDEX <= #{end}
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT request.REQUEST_NO AS requestNo, /* 요청번호 */ request.REQUEST_PURPOSE AS deployTypeCd, /* 배포유형 */ request.OBJECT_TYPE AS objectType, /* 자료구분 */ request.STATUS_CD AS statusCd, /* 진행상태 */ requestMapping.OBJECT_CLASS_CD2 AS objectClassCd2, /* 자료유형코드 */ requestMapping.OBJECT_CLASS_NM2 AS objectClassNm2, /* 자료유형 */ requestMapping.OBJECT_NO AS objectNo, /* 문서번호 */ requestMapping.OBJECT_NM AS objectNm, /* 문서명 */ requestMapping.REV_NO AS revNo, /* REV */ requestMapping.BUSINESS_AREA_CD AS businessAreaCd, /* 사업장코드 */ deployDept.DEPT_CD AS requestDeptCd, /* 배포부서 */ deployDept.DEPT_NM AS requestDeptNm, /* 배포부서 */ deployUser.USER_CD AS requestUserCd, /* 배포자 */ deployUser.USER_NM AS requestUserNm, /* 배포자 */ request.USE_START_YMD AS requestDt, /* 배포일 */ 0 AS deployCount, /* 배포매수 */ request.USE_END_YMD AS validPeriod, /* 유효기간 */ ( SELECT COUNT(DEPLOY_USER_CD) FROM DOCS_REQUEST_DEPLOY tmpDeploy WHERE tmpDeploy.REQUEST_NO = request.REQUEST_NO ) AS userCountToAccept, ( SELECT COUNT(DEPLOY_USER_CD) FROM DOCS_REQUEST_DEPLOY tmpDeploy WHERE tmpDeploy.REQUEST_NO = request.REQUEST_NO AND ACCEPT_YN = 'Y' ) AS accptUserCount FROM DOCS_REQUEST request INNER JOIN ( SELECT REQUEST_NO, MAX(OBJECT_ID) AS OBJECT_ID, 0 AS DEPLOY_COUNT FROM DOCS_REQUEST_MAPPING tmpMapping GROUP BY REQUEST_NO ) tmpMapping ON tmpMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = tmpMapping.REQUEST_NO AND requestMapping.OBJECT_ID = tmpMapping.OBJECT_ID INNER JOIN DOCS_USER deployUser ON deployUser.USER_CD = request.INSERT_USER_CD INNER JOIN DOCS_DEPT deployDept ON deployDept.DEPT_CD = deployUser.DEPT_CD WHERE REQUEST_TYPE = 'PRODUCT' AND REQUEST_PURPOSE IN ('NEW', 'REPLACE')
AND TO_DATE(request.USE_START_YMD, 'YYYY-MM-DD') BETWEEN TO_DATE(#{deployStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{deployEndDt}, 'YYYY-MM-DD')
AND objectNo LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND objectClassCd2 = #{objectClassCd2}
AND requestDeptCd = #{deptCd}
AND deployTypeCd = #{deployTypeCd}
AND requestUserCd = #{requestUserCd}
AND businessAreaCd = #{businessAreaCd}
AND objectType = #{objectType}
AND statusCd = #{statusCd}
) B1
